// Unit test for computeLegRiskScore — exercises each of the five factors in
// isolation, the roll-up + level tiers, ETA-uncertainty growth with cumulative
// time and wind reliability, edge/null cases, and the explainable factor shape.
async function testComputeLegRiskScore() {
  // Explicit weights so the test is independent of config values
  const W = {
    headwindAngleDeg: 60, headwindMinKnots: 10, strongWindKnots: 22,
    lowVisPrecipMm: 2, lowVisCloudPct: 95, pressureLowHpa: 1005, pressureDropHpa: 3,
    etaBasePct: 6, etaHeadwindMult: 1.8
  };

  // Fixed epoch + sun times so darkness/daylight is deterministic.
  const BASE = 1700000000000;
  const HOUR = 3600000;
  const sunsetDay = BASE + 6 * HOUR;   // sunset 6h AFTER arrival -> daylight
  const sunriseDay = BASE - 6 * HOUR;  // sunrise 6h BEFORE arrival -> daylight
  const sunsetDark = BASE - 1 * HOUR;  // sunset 1h BEFORE arrival -> darkness

  // Convenience wrapper
  const score = (bearing, hour, prev, arrive, sunset, sunrise, eta) =>
    functions.call('computeLegRiskScore', bearing, hour, prev, arrive, sunset, sunrise, eta, W);

  // A benign daylight hour helper
  const calmHour = { windSpeed: 4, windDirection: 270, windGusts: 5, precipitation: 0, cloudCover: 5, pressure: 1016 };

  // ===== Calm baseline: low score, all five factors present & well-formed =====
  const calm = score(90, calmHour, null, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 0 });
  assertEquals(calm.factors.length, 5, 'Always exposes exactly five factors');
  const keys = calm.factors.map((f) => f.key);
  assertEquals(keys.join(','), 'wind,visibility,pressure,sunset,eta', 'Factor order/keys are stable');
  const maxes = calm.factors.map((f) => f.max);
  assertEquals(maxes.join(','), '30,20,20,15,15', 'Factor caps are 30/20/20/15/15');
  assert(calm.score < 20, 'Benign conditions score in the low band');
  assertEquals(calm.level, 'low', 'Low band maps to level low');
  // Factor shape
  for (const f of calm.factors) {
    assert(typeof f.key === 'string' && f.key.length > 0, 'factor.key is a non-empty string');
    assert(typeof f.label === 'string' && f.label.length > 0, 'factor.label is a non-empty string');
    assert(typeof f.icon === 'string' && f.icon.length > 0, 'factor.icon is a non-empty string');
    assert(typeof f.points === 'number', 'factor.points is a number');
    assert(typeof f.max === 'number' && f.max > 0, 'factor.max is a positive number');
    assert(typeof f.detail === 'string' && f.detail.length > 0, 'factor.detail is a non-empty string');
    assert(f.points >= 0 && f.points <= f.max, 'factor.points is within 0..max');
  }
  assert(typeof calm.headline === 'string' && calm.headline.length > 0, 'headline is a non-empty string');

  // ===== Wind factor: headwind adds points vs the same-speed tailwind =====
  const headHour = { windSpeed: 16, windDirection: 90, windGusts: 18, precipitation: 0, cloudCover: 5, pressure: 1016 };
  const tailHour = { windSpeed: 16, windDirection: 270, windGusts: 18, precipitation: 0, cloudCover: 5, pressure: 1016 };
  const headwind = score(90, headHour, null, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 0 });
  const tailwind = score(90, tailHour, null, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 0 });
  assert(headwind.factors[0].points > tailwind.factors[0].points, 'Headwind raises the wind factor over a tailwind');

  // ===== Visibility factor: heavy precip drives points up =====
  const rainHour = { windSpeed: 5, windDirection: 270, windGusts: 5, precipitation: 4, cloudCover: 5, pressure: 1016 };
  const rain = score(90, rainHour, null, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 0 });
  assert(rain.factors[1].points >= 10, 'Heavy precip drives a strong visibility contribution');

  // ===== Pressure factor: low absolute + sharp fall =====
  const pressHour = { windSpeed: 5, windDirection: 270, windGusts: 5, precipitation: 0, cloudCover: 5, pressure: 998 };
  const press = score(90, pressHour, { pressure: 1004 }, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 0 });
  assert(press.factors[2].points >= 10, 'Low + falling pressure drives a strong pressure contribution');

  // ===== Sunset factor: arriving after sunset is full points =====
  const night = score(90, calmHour, null, BASE, sunsetDark, sunriseDay, { cumulativeHoursToArrival: 0 });
  assertEquals(night.factors[3].points, 15, 'Arrival in darkness maxes the sunset factor');

  // ===== ETA factor: grows with cumulative travel time =====
  const lullHour = { windSpeed: 8, windDirection: 270, windGusts: 8, precipitation: 0, cloudCover: 5, pressure: 1016 };
  const etaNear = score(90, lullHour, null, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 3 });
  const etaFar = score(90, lullHour, null, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 24 });
  assert(etaFar.factors[4].points > etaNear.factors[4].points, 'ETA uncertainty grows with cumulative hours');

  // ===== ETA factor: headwind degrades reliability vs tailwind, same hours =====
  const etaHead = score(90, headHour, null, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 12 });
  const etaTail = score(90, tailHour, null, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 12 });
  assert(etaHead.factors[4].points > etaTail.factors[4].points, 'Headwind raises ETA uncertainty at the same travel time');

  // ===== Roll-up + tiers: a stacked-risk leg lands in the severe band =====
  const nasty = { windSpeed: 30, windDirection: 90, windGusts: 42, precipitation: 6, cloudCover: 99, pressure: 995 };
  const severe = score(90, nasty, { pressure: 1002 }, BASE, sunsetDark, sunriseDay, { cumulativeHoursToArrival: 20 });
  assert(severe.score >= 70, 'Stacked hazards push the score into the severe band');
  assertEquals(severe.level, 'severe', 'Score >= 70 maps to level severe');
  assert(severe.score <= 100, 'Score never exceeds 100');
  const sum = severe.factors.reduce((s, f) => s + f.points, 0);
  assertEquals(sum, severe.score, 'Score equals the sum of factor points (meter segments add up)');
  assert(severe.headline.toLowerCase().indexOf('severe') >= 0, 'Headline names the severe level');

  // ===== A mid-band combo maps to moderate =====
  const modHour = { windSpeed: 16, windDirection: 90, windGusts: 20, precipitation: 0, cloudCover: 5, pressure: 1016 };
  const moderate = score(90, modHour, null, BASE, sunsetDark, sunriseDay, { cumulativeHoursToArrival: 6 });
  assert(moderate.score >= 20 && moderate.score < 45, 'Mid combo lands in the moderate band');
  assertEquals(moderate.level, 'moderate', 'Score 20..44 maps to level moderate');

  // ===== Edge cases: null hour data, null sun times, null eta context =====
  const edge = functions.call('computeLegRiskScore', 90, null, null, BASE, null, null, null, W);
  assertEquals(edge.factors.length, 5, 'Edge case still returns five factors');
  assertEquals(edge.score, 0, 'Fully benign/missing data scores zero');
  assertEquals(edge.level, 'low', 'Zero score is level low');
  assert(edge.factors[3].detail.indexOf('Sun times') >= 0, 'Unknown sun times are explained in the detail');

  // ===== Missing weights object must not throw (defensive defaults) =====
  const noWeights = functions.call('computeLegRiskScore', 90,
    { windSpeed: 25, windDirection: 90, windGusts: 30, precipitation: 0, cloudCover: 5, pressure: 1016 },
    null, BASE, sunsetDay, sunriseDay, { cumulativeHoursToArrival: 5 }, {});
  assert(typeof noWeights.score === 'number' && noWeights.factors.length === 5, 'Defaults apply when weights are empty');
}
